using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");

// Check overall build result
Console.WriteLine($"Build succeeded: {build.Succeeded}");
Console.WriteLine();

// Find all projects and their results
var projects = build.FindChildrenRecursive<Project>();
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
foreach (var p in projects)
{
    Console.WriteLine($"  {p.Name} -> Succeeded: {p.Succeeded}");
}
Console.WriteLine();

// Find all errors including from child projects
Console.WriteLine("=== ALL ERRORS (including cascading) ===");
var errors = build.FindChildrenRecursive<Error>();
foreach (var error in errors)
{
    var project = error.GetNearestParent<Project>();
    Console.WriteLine($"[{project?.Name ?? "?"}] {error.Code}: {error.Text}");
    if (!string.IsNullOrEmpty(error.File))
        Console.WriteLine($"  at {error.File}:{error.LineNumber}");
    Console.WriteLine();
}

// Check for project references to understand dependency chain
Console.WriteLine("=== PROJECT REFERENCES ===");
var items = build.FindChildrenRecursive<Item>();
foreach (var item in items.Where(i => i.Name == "ProjectReference"))
{
    var proj = item.GetNearestParent<Project>();
    Console.WriteLine($"  {proj?.Name} -> references: {item.Text}");
}
EOF
