using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");
Console.WriteLine($"Build succeeded: {build.Succeeded}");
Console.WriteLine();

// Find all projects
var projects = build.FindChildrenRecursive<Project>();
Console.WriteLine("=== PROJECTS ===");
foreach (var p in projects)
{
    var errs = p.FindChildrenRecursive<Error>();
    Console.WriteLine($"  {p.Name} (errors: {errs.Count})");
}
Console.WriteLine();

// All errors
Console.WriteLine("=== ALL ERRORS ===");
var errors = build.FindChildrenRecursive<Error>();
foreach (var error in errors)
{
    var project = error.GetNearestParent<Project>();
    Console.WriteLine($"[{project?.Name ?? "?"}] {error.Code}: {error.Text}");
    if (!string.IsNullOrEmpty(error.File))
        Console.WriteLine($"  at {error.File}:{error.LineNumber}");
    Console.WriteLine();
}

// Check package references for Services.csproj
Console.WriteLine("=== PACKAGE REFS IN Services.csproj ===");
var addItems = build.FindChildrenRecursive<AddItem>();
foreach (var ai in addItems.Where(a => a.Name == "PackageReference"))
{
    var proj = ai.GetNearestParent<Project>();
    if (proj?.Name?.Contains("Services") == true)
    {
        foreach (var item in ai.Children.OfType<Item>())
            Console.WriteLine($"  {item.Text}");
    }
}

// Also check for the source file content
Console.WriteLine();
Console.WriteLine("=== SOURCE FILE IN ERROR ===");
var sourceFiles = build.FindChildrenRecursive<SourceFile>();
foreach (var sf in sourceFiles)
{
    if (sf.Name?.Contains("UserService") == true)
        Console.WriteLine($"  {sf.Name}");
}
EOF
