using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");

// Look for all AddItem and NamedNode to find package references
Console.WriteLine("=== ALL PACKAGE REFERENCES (all projects) ===");
var namedNodes = build.FindChildrenRecursive<NamedNode>();
foreach (var node in namedNodes.Where(n => n.Name == "PackageReference"))
{
    var proj = node.GetNearestParent<Project>();
    Console.WriteLine($"  [{proj?.Name}] {node.GetType().Name}: {node}");
}

Console.WriteLine();
Console.WriteLine("=== LOOKING FOR DEPENDENCY CHAIN ===");
// Check ProjectReference items
var items = build.FindChildrenRecursive<Item>();
foreach (var item in items.Where(i => i.Name?.Contains("ProjectReference") == true || i.Name?.Contains("PackageReference") == true))
{
    var proj = item.GetNearestParent<Project>();
    if (proj?.Name?.Contains("Services") == true || proj?.Name?.Contains("Api") == true)
    {
        Console.WriteLine($"  [{proj?.Name}] {item.Name} = {item.Text}");
    }
}

// Check if Api depends on Services
Console.WriteLine();
Console.WriteLine("=== CHECKING Api -> Services dependency ===");
foreach (var item in items.Where(i => i.Text?.Contains("Services") == true))
{
    var proj = item.GetNearestParent<Project>();
    if (proj?.Name?.Contains("Api") == true)
        Console.WriteLine($"  [{proj?.Name}] {item.Name} = {item.Text}");
}
EOF
