var evals = build.FindChildrenRecursive<ProjectEvaluation>();
foreach (var ev in evals.Where(e => e.Name == "Services.csproj").Take(1))
{
    var imports = ev.FindChildrenRecursive<Import>();
    foreach (var imp in imports.Take(5))
        Console.WriteLine($"  Import: {imp.Name}");

    // Get properties
    Console.WriteLine();
    Console.WriteLine("  Properties:");
    var props = ev.FindChildrenRecursive<Property>();
    foreach (var p in props.Where(p => p.Name == "TargetFramework" || p.Name == "RootNamespace" || p.Name == "PackageReference"))
        Console.WriteLine($"    {p.Name} = {p.Value}");
}

// Let's look for NuGet restore messages
Console.WriteLine();
Console.WriteLine("=== RESTORE MESSAGES ===");
var messages = build.FindChildrenRecursive<Message>();
foreach (var msg in messages.Where(m => m.Text?.Contains("Newtonsoft") == true))
{
    Console.WriteLine($"  {msg.Text}");
}

// Look at the project file content via the target
Console.WriteLine();
Console.WriteLine("=== LOOKING FOR project.assets.json info ===");
foreach (var msg in messages.Where(m => m.Text?.Contains("Services") == true && m.Text?.Contains("PackageReference") == true).Take(5))
