    foreach (var e in errs)
        Console.WriteLine($"  {e.Code}: {e.Text}");
}

// Check for MSB4181 or similar cascade errors
Console.WriteLine();
Console.WriteLine("=== ALL MESSAGES containing 'failed' or 'skipped' ===");
foreach (var msg in messages.Where(m => m.Text?.Contains("not build") == true || 
    m.Text?.Contains("previously failed") == true ||
    m.Text?.Contains("skipping") == true).Take(10))
{
    var proj = msg.GetNearestParent<Project>();
    Console.WriteLine($"  [{proj?.Name}] {msg.Text}");
}
EOF
