using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");

// Get the full tree structure for Services.csproj evaluation
var evals = build.FindChildrenRecursive<ProjectEvaluation>();
foreach (var ev in evals.Where(e => e.Name == "Services.csproj").Take(1))
{
    Console.WriteLine($"=== Services.csproj Evaluation Tree ===");
    PrintTree(ev, 0, 3);
}

void PrintTree(BaseNode node, int depth, int maxDepth)
{
    if (depth > maxDepth) return;
    var indent = new string(' ', depth * 2);
    Console.WriteLine($"{indent}{node.GetType().Name}: {node}");
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children.Take(30))
            PrintTree(child, depth + 1, maxDepth);
    }
}
EOF
