    var addItems = ev.FindChildrenRecursive<AddItem>();
    foreach (var ai in addItems.Where(a => a.Name == "PackageReference" || a.Name == "ProjectReference"))
    {
        Console.WriteLine($"  {ai.Name}:");
        foreach (var item in ai.Children.OfType<Item>())
        {
            Console.WriteLine($"    {item.Text}");
            foreach (var meta in item.Children.OfType<Metadata>())
                Console.WriteLine($"      {meta.Name} = {meta.Value}");
        }
    }
}

